using Microsoft.AspNetCore.Http;
using System.Net.Http;
using System.Threading.Tasks;

public class WebhookProxy
{
    private readonly IHttpClientFactory _httpClientFactory;

    public WebhookProxy(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    public async Task<IActionResult> ForwardRequest(HttpRequest request)
    {
        string userUrl = request.Query["url"];

        if (string.IsNullOrEmpty(userUrl))
        {
            return BadRequest("Missing 'url' query parameter.");
        }

        HttpClient httpClient = _httpClientFactory.CreateClient();

        HttpResponseMessage response = await httpClient.GetAsync(userUrl);

        return new ContentResult
        {
            Content = await response.Content.ReadAsStringAsync(),
            StatusCode = (int)response.StatusCode
        };
    }
}